package main

import (
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe load balancers,
// pipes the output to jq for formatting, and writes the result to a file.
// It returns the content of the output file and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	// Command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	// Command: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun's stdout to jq's stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %w", err)
	}

	// Set jq's stdin to the pipe from aliyun
	cmdJq.Stdin = pipe

	// Create the output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer file.Close()

	// Set jq's stdout to the output file
	cmdJq.Stdout = file

	// Start jq first to ensure it is ready to consume input
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Start aliyun command
	if err := cmdAliyun.Start(); err != nil {
		// If aliyun fails to start, terminate jq to prevent hanging
		cmdJq.Process.Kill()
		return "", fmt.Errorf("failed to start aliyun: %w", err)
	}

	// Wait for aliyun to finish
	// This closes the write end of the pipe when done, signaling EOF to jq
	if err := cmdAliyun.Wait(); err != nil {
		cmdJq.Process.Kill()
		return "", fmt.Errorf("aliyun command execution failed: %w", err)
	}

	// Wait for jq to finish processing
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command execution failed: %w", err)
	}

	// Read the generated file content to return as result
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(content), nil
}

func main() {
	// Example usage of QuerySLBAndExport
	// In a production environment, loadBalancerName and outputFile should be passed via flags or arguments
	loadBalancerName := "my-load-balancer"
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error executing query: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Query successful. Output written to %s\n", outputFile)
	fmt.Printf("Content:\n%s\n", result)
}

