	// Check for shell metacharacters that could enable injection
	dangerousChars := []string{"`", "$", "\n", "\r", "\t", "|", ">", "<", "&", ";", "(", ")", "{", "}", "[", "]", "\\", "\"", "'"}
	for _, char := range dangerousChars {
		if strings.Contains(input, char) {
