// QuerySLBAndExport executes the aliyun SLB query command and exports the result to a file
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe between aliyun and jq
	aliyunOutput, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}

	jqCmd.Stdin = aliyunOutput

	// Capture jq output
	var jqOutput bytes.Buffer
	jqCmd.Stdout = &jqOutput

	// Capture stderr for better error reporting
	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	// Write output to file
	if err := os.WriteFile(outputFile, jqOutput.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return jqOutput.String(), nil
}

func main() {
