	}

	// Write output to file with safe permissions
	if err := os.WriteFile(cleanPath, outputBytes, 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(outputBytes), nil
}

// isValidLoadBalancerName validates the load balancer name
// Only allows alphanumeric characters, hyphens, and underscores
func isValidLoadBalancerName(name string) bool {
