package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation for loadBalancerName
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}

	// Check for dangerous characters in loadBalancerName to prevent injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>&;(){}[]\\\"'") {
		return "", fmt.Errorf("invalid characters in loadBalancerName")
	}

	// Input validation for outputFile
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Prevent path traversal attacks
	cleanPath := filepath.Clean(outputFile)
	if strings.HasPrefix(cleanPath, "..") {
		return "", fmt.Errorf("invalid outputFile path: path traversal detected")
	}

	// Create the aliyun command with arguments as separate parameters (safe from injection)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Execute aliyun command and capture output
	aliyunOutput, err := aliyunCmd.Output()
	if err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set jq's stdin to aliyun's output
	jqCmd.Stdin = bytes.NewReader(aliyunOutput)

	// Execute jq and capture output
	jqOutput, err := jqCmd.Output()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Write output to file
	err = os.WriteFile(cleanPath, jqOutput, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(jqOutput), nil
}

