	return string(jqOutput), nil
}

// isValidLoadBalancerName validates the load balancer name
// Only allows alphanumeric characters, hyphens, and underscores
func isValidLoadBalancerName(name string) bool {
	if len(name) == 0 || len(name) > 128 {
		return false
	}
	// Only allow alphanumeric, hyphen, underscore
	for _, c := range name {
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '-' || c == '_') {
			return false
		}
	}
	return true
}

// isValidOutputPath validates the output file path
// Prevents path traversal and ensures safe file paths
func isValidOutputPath(path string) bool {
	if len(path) == 0 {
		return false
	}

	// Check for path traversal attempts
	if strings.Contains(path, "..") {
		return false
	}

	// Ensure path doesn't start with / (absolute path)
	if filepath.IsAbs(path) {
		return false
	}

	// Check for null bytes
	if strings.Contains(path, "\x00") {
		return false
	}

	// Check for other dangerous characters
	dangerousChars := []string{";", "|", "&", "$", "`", ">", "<", "(", ")", "{", "}", "[", "]", "\\", "\n", "\r", "\t"}
	for _, char := range dangerousChars {
		if strings.Contains(path, char) {
			return false
		}
	}

	return true
}

