// QuerySLBAndExport executes the aliyun CLI command to query SLB information
// and exports the formatted output to a file using jq
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Build the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun output to jq input
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}

	// Set jq's stdin to read from aliyun's stdout
	jqCmd.Stdin = pipe

	// Capture jq's output
	var jqOutput strings.Builder
	jqCmd.Stdout = &jqOutput

	// Set stderr for both commands
	aliyunCmd.Stderr = os.Stderr
	jqCmd.Stderr = os.Stderr

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Run jq command (this will wait for aliyun to complete)
	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to run jq command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Write output to file
	outputContent := jqOutput.String()
	if err := os.WriteFile(outputFile, []byte(outputContent), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return outputContent, nil
}

func main() {
