package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation - check for empty strings
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Validate outputFile path to prevent directory traversal
	if strings.Contains(outputFile, "..") {
		return "", fmt.Errorf("invalid outputFile path: directory traversal detected")
	}

	// Validate loadBalancerName to prevent command injection
	// Only allow alphanumeric characters, hyphens, underscores, and spaces
	validChars := true
	for _, r := range loadBalancerName {
		if !((r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '-' || r == '_' || r == ' ') {
			validChars = false
			break
		}
	}
	if !validChars {
		return "", fmt.Errorf("invalid characters in loadBalancerName")
	}

	// Create the aliyun command with proper argument passing (no shell injection)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up piping: aliyun output -> jq input
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}

	jqCmd.Stdin = pipe

	// Start aliyun command FIRST before jq tries to read from the pipe
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Process.Kill()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to complete and close the pipe
	if err := aliyunCmd.Wait(); err != nil {
		jqCmd.Process.Kill()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq command to complete and get output
	jqOutput, err := jqCmd.Output()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Write output to file
	outputStr := string(jqOutput)
	if err := os.WriteFile(outputFile, jqOutput, 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return outputStr, nil
}

