package main

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate loadBalancerName - only allow safe characters
	if !isValidLoadBalancerName(loadBalancerName) {
		return "", fmt.Errorf("invalid load balancer name: contains unsafe characters")
	}

	// Validate and sanitize output file path
	if !isValidOutputPath(outputFile) {
		return "", fmt.Errorf("invalid output file path: potential path traversal or unsafe characters")
	}

	// Execute aliyun command directly without shell interpretation
	// This prevents shell injection attacks
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunOutput, err := aliyunCmd.Output()
	if err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Execute jq command directly without shell interpretation
	// Pass aliyun output as stdin to jq
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = strings.NewReader(string(aliyunOutput))
	jqOutput, err := jqCmd.Output()
	if err != nil {
		return "", fmt.Errorf("jq processing failed: %w", err)
	}

	// Write output to file using Go's file operations (not shell redirection)
	err = os.WriteFile(outputFile, jqOutput, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(jqOutput), nil
}

// isValidLoadBalancerName validates that the load balancer name contains only safe characters
func isValidLoadBalancerName(name string) bool {
	if len(name) == 0 || len(name) > 128 {
		return false
	}
	// Only allow alphanumeric characters, hyphens, and underscores
	for _, c := range name {
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '-' || c == '_') {
			return false
		}
	}
	return true
}

// isValidOutputPath validates the output file path to prevent path traversal and unsafe operations
func isValidOutputPath(path string) bool {
	if len(path) == 0 {
		return false
	}
	// Prevent path traversal attacks
	if strings.Contains(path, "..") {
		return false
	}
	// Prevent absolute paths that could write to sensitive locations
	if filepath.IsAbs(path) {
		return false
	}
	// Clean the path and verify it doesn't escape intended directory
	cleanPath := filepath.Clean(path)
	if strings.HasPrefix(cleanPath, "..") {
		return false
	}
	// Ensure file extension is .json for safety
	if !strings.HasSuffix(strings.ToLower(path), ".json") {
		return false
	}
	// Check for null bytes or other dangerous characters
	if strings.ContainsAny(path, "\x00\n\r\t") {
		return false
	}
	return true
}

