package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation - check for dangerous characters to prevent command injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>&;(){}[]\\\"'") {
		return "", fmt.Errorf("invalid characters in loadBalancerName")
	}

	if strings.ContainsAny(outputFile, "`$\n\r\t|>&;(){}[]\\\"'") {
		return "", fmt.Errorf("invalid characters in outputFile")
	}

	// Validate file path to prevent path traversal attacks
	cleanPath := filepath.Clean(outputFile)
	if strings.Contains(cleanPath, "..") {
		return "", fmt.Errorf("path traversal detected in outputFile")
	}

	// Create the aliyun command with proper argument separation (no shell interpretation)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun stdout to jq stdin
	pipeReader, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	defer pipeReader.Close()

	jqCmd.Stdin = pipeReader

	// Capture jq output
	var jqOutput bytes.Buffer
	jqCmd.Stdout = &jqOutput

	// Capture stderr from both commands
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Process.Kill()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to complete
	aliyunErr := aliyunCmd.Wait()

	// Wait for jq command to complete
	jqErr := jqCmd.Wait()

	// Check for errors
	if aliyunErr != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, aliyunStderr.String())
	}

	if jqErr != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, jqStderr.String())
	}

	// Write jq output to file
	outputData := jqOutput.Bytes()
	if err := os.WriteFile(outputFile, outputData, 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(outputData), nil
}

func main() {
	// Example usage
	output, err := QuerySLBAndExport("my-slb", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Output: %s\n", output)
}

